diagrams.mermaid:
classDiagram
  class PaymentController {
    +pay(req) Response
  }
  class PaymentService {
    +approve(order) Result
  }
  class ConnectionPool {
    -max: int = 20
    +acquire() Conn
    +release(c)
  }
  class LeakyQuery {
    +run() void
  }
  PaymentController --> PaymentService
  PaymentService --> ConnectionPool
  PaymentService --> LeakyQuery
  LeakyQuery ..> ConnectionPool : 커넥션 미반환

flowchart TD
  sym["결제 5% 실패(500)"] --> h1["외부 PG 타임아웃?"]
  sym --> h2["앱 CPU 포화?"]
  sym --> h3["DB 커넥션 풀 고갈"]
  h3 --> r["커넥션 누수 쿼리"]
  classDef reject fill:#eaeef2,stroke:#afb8c1,color:#8c959f;
  classDef confirm fill:#ffebe9,stroke:#cf222e,color:#cf222e;
  class h1,h2 reject;
  class sym,h3,r confirm;
